// @ts-check

import { build } from "esbuild";
import { fileURLToPath } from "node:url";
import path from "node:path";

const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url));
export const PROJECT_ROOT = path.resolve(SCRIPT_DIR, "../..");
export const REPORT_BUNDLE_PATH = path.join(
  PROJECT_ROOT,
  "src/peval_py/assets/report.js",
);

const GENERATED_BANNER =
  "// Generated by `npm run build` from web/src/main.js. Do not edit directly.";

export async function buildReportBundle() {
  const result = await build({
    absWorkingDir: PROJECT_ROOT,
    entryPoints: ["web/src/main.js"],
    outfile: "src/peval_py/assets/report.js",
    bundle: true,
    format: "esm",
    platform: "browser",
    target: ["es2022"],
    splitting: false,
    external: [],
    write: false,
    minify: false,
    sourcemap: false,
    charset: "utf8",
    legalComments: "none",
    treeShaking: false,
    metafile: true,
    banner: { js: GENERATED_BANNER },
    logLevel: "silent",
  });

  if (result.outputFiles.length !== 1) {
    throw new Error(`expected one report bundle, got ${result.outputFiles.length}`);
  }
  const outputs = Object.values(result.metafile.outputs);
  const externalImports = outputs.flatMap((output) => output.imports);
  if (externalImports.length) {
    throw new Error(
      `report bundle contains external imports: ${externalImports.map((item) => item.path).join(", ")}`,
    );
  }
  const bytes = Buffer.from(result.outputFiles[0].contents);
  if (/<\/script/i.test(bytes.toString("utf8"))) {
    throw new Error("report bundle contains a literal closing script tag");
  }
  return bytes;
}
